#include<iostream>#include<vector>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        string s;        cin>>s;        int n= s.length();        int total_ones=0;        for(char c:s)if(c=='1')total_ones++;        int total_zeros= n- total_ones;        int pref_one=0;        int pref_zero=0;        int ans= min(total_ones,total_zeros);        for(int i=0;i<n;i++){            if(s[i]=='1'){                pref_one++;            }else pref_zero++;            int suff_one= total_ones- pref_one;            int suff_zero= total_zeros- pref_zero;            ans= min(ans, min(pref_one + suff_zero, pref_zero + suff_one));         }        cout<<ans<<"\n";    }}